import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Subir Logs","description":"Como subir logs para solucionar problemas.","frontmatter":{"title":"Subir Logs","description":"Como subir logs para solucionar problemas.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.4/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.4/translated/es_es/players/troubleshooting/uploading-logs.md","lastUpdated":1760721669000}`);var a={name:`es_es/1.21.4/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Subir Logs <a class="header-anchor" href="#h1" aria-label="Permalink to “Subir Logs”">​</a></h1><p>Durante la solución de problemas, muchas veces es necesario proveer los logs para ayudar a identificar la causa del problema.</p><h2 id="¿porque-deberia-subir-los-logs" tabindex="-1">¿Porqué debería subir los logs? <a class="header-anchor" href="#¿porque-deberia-subir-los-logs" aria-label="Permalink to “¿Porqué debería subir los logs?”">​</a></h2><p>Subir los logs le permite a otros ayudarte a solucionar tus problemas más rápido comparado a simplemente pegar los logs en un chat o en una publicación de foro. También te permite compartir tus logs con otros sin tener que copiar y pegarlos.</p><p>Algunos sitios para pegar texto también remarcan la sintaxis del log, lo cual los hace más facil de leer, y pueden censurar información sensible, como tu nombre de usuario, o información de sistema.</p><h2 id="reportes-de-crasheos" tabindex="-1">Reportes de Crasheos <a class="header-anchor" href="#reportes-de-crasheos" aria-label="Permalink to “Reportes de Crasheos”">​</a></h2><p>Los reportes de crasheo son generados automáticamente cuando tu juego crashea. Solo contienen información sobre el crasheo, más no los logs enteros del juego. Están en el folder de <code>crash-reports</code> en el folder del juego.</p><p>Para más información sobre los reportes de crasheo, visita <a href="./crash-reports">Reportes de Crasheo</a>.</p><h2 id="encontrar-los-logs" tabindex="-1">Encontrar los Logs <a class="header-anchor" href="#encontrar-los-logs" aria-label="Permalink to “Encontrar los Logs”">​</a></h2><p>Esta guía cubre el launcher oficial de Minecraft (comúnmente referido como el &quot;launcher vanilla&quot;) - para launchers de terceros, puedes consultar su documentación.</p><p>El folder del juego puede ser encontrado en los siguientes lugares dependiendo de tu sistema operativo:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>El log más recient se llama <code>latest.log</code>, mientras que logs anteriores utilizan un patrón de nombramiento como este: <code>aaaa-mm-dd_numero.log.gz</code>.</p><h2 id="subir-logs" tabindex="-1">Subir Logs <a class="header-anchor" href="#subir-logs" aria-label="Permalink to “Subir Logs”">​</a></h2><p>Los logs pueden ser subidos en una variedad de servicios, como:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};